<span class="line">        ctx<span class="token punctuation">.</span><span class="token function">drawImage</span><span class="token punctuation">(</span>can2<span class="token punctuation">,</span> x <span class="token operator">*</span> <span class="token number">2</span> <span class="token operator">-</span> MagR<span class="token punctuation">,</span> y <span class="token operator">*</span> <span class="token number">2</span> <span class="token operator">-</span> MagR<span class="token punctuation">,</span> <span class="token number">300</span><span class="token punctuation">,</span> <span class="token number">300</span><span class="token punctuation">,</span> x <span class="token operator">-</span> MagR<span class="token punctuation">,</span> y <span class="token operator">-</span> MagR<span class="token punctuation">,</span> <span class="token number">300</span><span class="token punctuation">,</span> <span class="token number">300</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
